import React, { useState, useEffect, useContext } from "react";
import { AuthContext } from "../AuthContext";
import "./VendedorDashboard.css";

function VendedorDashboard() {
  const { user } = useContext(AuthContext);
  const [pedidos, setPedidos] = useState([]);
  const [mes, setMes] = useState("");

  useEffect(() => {
    if (user && user.id_usuario) {
      cargarPedidos();
    }
  }, [user, mes]);

  const cargarPedidos = () => {
    if (!user || !user.id_usuario) return; // protección extra
    let url = `http://localhost:3001/vendedor/pedidos/${user.id_usuario}`;
    if (mes) url += `?mes=${mes}`;
    fetch(url)
      .then((res) => {
        if (!res.ok) {
          throw new Error("Error en la respuesta del servidor");
        }
        return res.json();
      })
      .then((data) => setPedidos(data))
      .catch((err) => console.error("Error cargando pedidos:", err));
  };

  if (!user) {
    return <p>Cargando usuario...</p>; // evita romper si user es null
  }

  return (
    <div className="vendedor-dashboard">
      <header className="topbar">
        <h2>Bienvenido, {user?.nombre || "Vendedor"}</h2>
      </header>

      <section className="filtro">
        <label>Filtrar por mes:</label>
        <select value={mes} onChange={(e) => setMes(e.target.value)}>
          <option value="">Todos</option>
          <option value="1">Enero</option>
          <option value="2">Febrero</option>
          <option value="3">Marzo</option>
          <option value="4">Abril</option>
          <option value="5">Mayo</option>
          <option value="6">Junio</option>
          <option value="7">Julio</option>
          <option value="8">Agosto</option>
          <option value="9">Septiembre</option>
          <option value="10">Octubre</option>
          <option value="11">Noviembre</option>
          <option value="12">Diciembre</option>
        </select>
      </section>

      <section className="tabla-pedidos">
        <h3>Histórico de pedidos</h3>
        <table>
          <thead>
            <tr>
              <th>ID Pedido</th>
              <th>ID Cliente</th>
              <th>Estado</th>
              <th>Fecha</th>
              <th>Prioridad</th>
            </tr>
          </thead>
          <tbody>
            {pedidos.length === 0 ? (
              <tr><td colSpan="5">No hay pedidos</td></tr>
            ) : (
              pedidos.map((p) => (
                <tr key={p.id_pedido}>
                  <td>{p.id_pedido}</td>
                  <td>{p.id_cliente}</td>
                  <td>{p.estado}</td>
                  <td>{new Date(p.fecha).toLocaleDateString()}</td>
                  <td>{p.prioridad}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </section>
    </div>
  );
}

export default VendedorDashboard;
